import spoon.reflect.CtModel;
import spoon.reflect.code.CtFieldAccess;
import spoon.reflect.code.CtImport;
import spoon.reflect.code.CtTypeAccess;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtField;
import spoon.reflect.declaration.CtImportContainer;
import spoon.reflect.declaration.CtType;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtFieldReference;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;
import spoon.reflect.visitor.chain.CtScannerListener;
import spoon.reflect.visitor.chain.ScanningMode;
import spoon.reflect.visitor.chain.CtConsumer;
import spoon.reflect.visitor.chain.CtQueryable;
import spoon.reflect.visitor.Query;

import java.io.File;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        // This is a generic transformation for CertificationPermission API change
        // from eu.europa.esig.dss.pades to eu.europa.esig.dss.enumerations

        if (args.length < 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        // Create Spoon factory
        spoon.Launcher launcher = new spoon.Launcher();
        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(sourceDirectory + "/processed");
        launcher.getEnvironment().setComplianceLevel(8);

        // Process the code
        CtModel model = launcher.buildModel();
        Factory factory = model.getFactory();

        // Find all imports of CertificationPermission from pades package
        List<CtImport> imports = model.getElements(new TypeFilter<>(CtImport.class));
        for (CtImport imp : imports) {
            String importPath = imp.getReference().toString();
            if (importPath.equals("eu.europa.esig.dss.pades.CertificationPermission")) {
                // Replace the import with the new location
                imp.setReference(factory.createTypeReference("eu.europa.esig.dss.enumerations.CertificationPermission"));
            }
        }

        // Find all references to CertificationPermission in the pades package
        List<CtTypeAccess> typeAccesses = model.getElements(new TypeFilter<>(CtTypeAccess.class));
        for (CtTypeAccess typeAccess : typeAccesses) {
            if (typeAccess.getAccessedType().toString().equals("eu.europa.esig.dss.pades.CertificationPermission")) {
                // Replace with new location
                typeAccess.setAccessedType(factory.createTypeReference("eu.europa.esig.dss.enumerations.CertificationPermission"));
            }
        }

        // Find all field access expressions that reference CertificationPermission
        List<CtFieldAccess> fieldAccesses = model.getElements(new TypeFilter<>(CtFieldAccess.class));
        for (CtFieldAccess fieldAccess : fieldAccesses) {
            if (fieldAccess.getType().toString().equals("eu.europa.esig.dss.pades.CertificationPermission")) {
                fieldAccess.setType(factory.createTypeReference("eu.europa.esig.dss.enumerations.CertificationPermission"));
            }
        }

        // Generate the modified code
        launcher.process();
        launcher.writeProcessedFiles();

        System.out.println("Transformation completed successfully");
    }
}

